#include<bits/stdc++.h>
using namespace std;
int main() {
	int m,a,b,c,book,cnt,ans;
	cin>>m;
	for(int i=1; i<=m; i++) {
		cnt=0;
		ans=0;
		cin>>a;
		c=b=a;
		while(b) {
			b/=10;
			ans++;
		}
		while(a) {
			book=a%10;
			cnt=cnt+pow(book,ans);
			a/=10;
		}
		if(cnt==c) {
			cout<<"T"<<endl;
		} else {
			cout<<"F"<<endl;
		}
	}
	return 0;
}
